// ─── HELPER FUNCTIONS ─────────────────────────────────────────────────────
export const getByCategory = (categoryId) =>
  vocabulary.filter((v) => v.category === categoryId);

export const getRandomWords = (count = 10, categoryId = null) => {
  const pool = categoryId ? getByCategory(categoryId) : vocabulary;
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
};

export const getById = (id) => vocabulary.find((v) => v.id === id);

export const totalCount = vocabulary.length;
